  for (let i = 0; i < lines.length; i++) {
    const line = lines[i].trim();
    if (!line.startsWith('|')) continue;
    if (/^\|\s*-/.test(line)) continue;
    const cells = line
      .split('|')
      .map(function (c) { return cleanMd(c); })
      .filter(function (c) { return c.length > 0; });
