  if (la === lb) return 1;
  if (la.indexOf(lb) >= 0 || lb.indexOf(la) >= 0) return 0.75;
  const ta = la.split(' ').filter(Boolean);
  const tb = lb.split(' ').filter(Boolean);
  if (!ta.length || !tb.length) return 0;
  let common = 0;
