      mapB[unitsB[j].id] = unitsB[j];
    }
  }

  const diffs = [];
  const seenB = {};

  for (const id in mapA) {
    const a = mapA[id];
    const b = mapB[id];
    if (!b) {
      diffs.push({
        type: 'missing_in_doc',
        id: id,
        label: a.label,
        templateText: a.text,
        docText: '',
        severity: classifySeverity(a.text, '')
