    let bestScore = 0;
    for (let j = 0; j < unitsB.length; j++) {
      if (usedB[j]) continue;
      const score = blockSimilarity(a, unitsB[j]);
      if (score > bestScore) {
        bestScore = score;
        bestJ = j;
      }
    }
    if (bestJ >= 0 && bestScore >= 0.35) {
      usedB[bestJ] = true;
      const b = unitsB[bestJ];
      if (normalizeCompareText(a.text) !== normalizeCompareText(b.text)) {
        diffs.push({
          type: 'text_mismatch',
          id: a.id,
          label: a.label || b.label,
          templateText: a.text,
          docText: b.text,
          severity: classifySeverity(a.text, b.text)
        });
      }
    } else {
      diffs.push({
        type: 'missing_in_doc',
        id: a.id,
        label: a.label,
        templateText: a.text,
        docText: '',
        severity: 'warning'
      });
    }
  }

  for (let j = 0; j < unitsB.length; j++) {
    if (usedB[j]) continue;
    diffs.push({
      type: 'missing_in_template',
      id: unitsB[j].id,
      label: unitsB[j].label,
      templateText: '',
      docText: unitsB[j].text,
      severity: 'info'
    });
  }

  return diffs;
