      reason: 'ready',
      raw: trimmed,
      schema: schema,
      body_text: bodyText,
      body_length: bodyText.length
    };
  } catch (e) {
    const jsonStart = trimmed.indexOf('{"schema"');
    if (jsonStart >= 0) {
      try {
        return tryParseR7SnapshotRaw(trimmed.slice(jsonStart));
      } catch (e2) {
        /* continue */
      }
    }
    if (looksLikeBase64(trimmed)) {
      const decoded = decodeBase64Utf8(trimmed);
      if (decoded) {
        const inner = tryParseR7SnapshotRaw(decoded);
        if (inner.ok) return inner;
      }
    }
    if (trimmed.indexOf('{') !== 0 && trimmed.length >= R7_MIN_BODY_CHARS) {
